const fs = require('fs');
const content = fs.readFileSync('input.txt', 'utf-8');
const lines = content.split('\n');
console.log(lines[0]);

try (BufferedReader br = new BufferedReader(new FileReader("input.txt"))) {
  String line = br.readLine();
  System.out.println(line);
}
